(function(){'use strict';document.querySelectorAll('form').forEach(function(f){f.addEventListener('submit',function(){var b=f.querySelector('[type="submit"]');if(!b||b.disabled)return;b.setAttribute('data-original-html',b.innerHTML);b.disabled=true;b.innerHTML='<span class="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>Обработване...';});});window.addEventListener('pageshow',function(e){if(e.persisted){document.querySelectorAll('[data-original-html]').forEach(function(b){b.innerHTML=b.getAttribute('data-original-html');b.disabled=false;b.removeAttribute('data-original-html');});}});})();